(()=>{function c(){let e=document.getElementById("sidebar"),t=document.getElementById("sidebar-overlay"),i=document.getElementById("sidebar-toggle");if(!e||!t||!i)return;function s(){e.classList.add("is-open"),t.classList.add("is-visible")}function n(){e.classList.remove("is-open"),t.classList.remove("is-visible")}i.addEventListener("click",()=>{e.classList.contains("is-open")?n():s()}),t.addEventListener("click",n),e.querySelectorAll("a").forEach(o=>{o.addEventListener("click",n)})}function a(){let e=window.location.pathname.split("/").pop()||"index.html";document.querySelectorAll(".sidebar__link").forEach(t=>{let i=t.getAttribute("href")||"";(i===e||e===""&&i==="index.html")&&(t.setAttribute("aria-current","page"),t.classList.add("sidebar__link--active"))})}document.addEventListener("DOMContentLoaded",()=>{c(),a()});})();
